(function(global){"use strict";var WORDLIST=null;var WORDLIST_URL="/assets/js/bip39-wordlist.json";async function loadWordlist(){if(WORDLIST)return WORDLIST;var resp=await fetch(WORDLIST_URL);WORDLIST=await resp.json();return WORDLIST;}function mnemonicToEntropy(mnemonic,wordlist){var words=mnemonic.trim().normalize("NFKD").split(/\s+/);if(words.length!==24)throw new Error("Expected 24-word mnemonic, got "+words.length);var bits="";for(var i=0;i<words.length;i++){var idx=wordlist.indexOf(words[i]);if(idx===-1)throw new Error("Unknown word: "+words[i]);bits+=idx.toString(2).padStart(11,"0");}var entropyBits=bits.slice(0,256);var entropy=new Uint8Array(32);for(var i=0;i<32;i++){entropy[i]=parseInt(entropyBits.slice(i*8,i*8+8),2);}return entropy;}global.BIP39={loadWordlist:loadWordlist,mnemonicToEntropy:async function(mnemonic){var wl=await loadWordlist();return mnemonicToEntropy(mnemonic,wl);}};})(typeof window!=="undefined"?window:globalThis);
